3	import { AnimatePresence } from "motion/react";
4	import { useParams } from "next/navigation";
5	import {
6	  Fragment,
7	  useCallback,
8	  useEffect,
9	  useMemo,
10	  useRef,
11	  useState,
12	} from "react";
13	
14	import CreatedByGAIABanner from "@/features/chat/components/banners/CreatedByGAIABanner";
15	import ChatBubbleBot from "@/features/chat/components/bubbles/bot/ChatBubbleBot";
16	import SearchedImageDialog from "@/features/chat/components/bubbles/bot/SearchedImageDialog";
17	import ChatBubbleUser from "@/features/chat/components/bubbles/user/ChatBubbleUser";
18	import GeneratedImageSheet from "@/features/chat/components/image/GeneratedImageSheet";
19	import { LoadingIndicator } from "@/features/chat/components/interface/LoadingIndicator";
20	import MemoryModal from "@/features/chat/components/memory/MemoryModal";
21	import { WelcomeChat } from "@/features/chat/components/welcome/WelcomeChat";
22	import { useConversation } from "@/features/chat/hooks/useConversation";
23	import { useConversationList } from "@/features/chat/hooks/useConversationList";
24	import { useLoading } from "@/features/chat/hooks/useLoading";
25	import { useLoadingText } from "@/features/chat/hooks/useLoadingText";
26	import { useRetryMessage } from "@/features/chat/hooks/useRetryMessage";
27	import {
28	  filterEmptyMessagePairs,
29	  isBotMessageEmpty,
30	} from "@/features/chat/utils/messageContentUtils";
31	import { getMessageProps } from "@/features/chat/utils/messagePropsUtils";
32	import { useUserStore } from "@/stores/userStore";
33	import type {
34	  ChatBubbleBotProps,
35	  SetImageDataType,
36	} from "@/types/features/chatBubbleTypes";
37	import type { MessageType } from "@/types/features/convoTypes";
38	
39	interface ChatRendererProps {
40	  convoMessages?: MessageType[];
41	}
42	
43	export default function ChatRenderer({
44	  convoMessages: propConvoMessages,
45	}: ChatRendererProps) {
46	  const { convoMessages: storeConvoMessages } = useConversation();
47	  const convoMessages = propConvoMessages ?? storeConvoMessages;
48	  const { conversations } = useConversationList();
49	  const [openGeneratedImage, setOpenGeneratedImage] = useState<boolean>(false);
50	  const [openMemoryModal, setOpenMemoryModal] = useState<boolean>(false);
51	  const { isLoading } = useLoading();
52	  const { loadingText, loadingTextKey, toolInfo } = useLoadingText();
53	  const { id: convoIdParam } = useParams<{ id: string }>();
54	  const scrolledToMessageRef = useRef<string | null>(null);
55	  const { retryMessage, isRetrying } = useRetryMessage();
56	  const [imageData, setImageData] = useState<SetImageDataType>({
57	    src: "",
58	    prompt: "",
59	    improvedPrompt: "",
60	  });
61	
62	  const conversation = useMemo(() => {
63	    return conversations.find(
64	      (convo) => convo.conversation_id === convoIdParam,
65	    );
66	  }, [conversations, convoIdParam]);
67	
68	  const welcomeConvoId = useUserStore(
69	    (s) => s.onboarding?.first_message_conversation_id,
70	  );
71	  const isWelcomeConversation =
72	    !!convoIdParam && !!welcomeConvoId && convoIdParam === welcomeConvoId;
73	
74	  // Handle retry callback
75	  const handleRetry = useCallback(
76	    (msgId: string) => {
77	      if (!convoIdParam) return;
78	      retryMessage(convoIdParam, msgId);
79	    },
80	    [convoIdParam, retryMessage],
81	  );
82	
83	  // Create options object for getMessageProps
84	  const messagePropsOptions = useMemo(
85	    () => ({
86	      conversation: conversation
87	        ? {
88	            is_system_generated: conversation.is_system_generated,
89	            system_purpose: conversation.system_purpose ?? undefined,
90	          }
91	        : undefined,
92	      setImageData,
93	      setOpenGeneratedImage,
94	      setOpenMemoryModal,
95	      onRetry: handleRetry,
96	      isRetrying,
97	    }),
98	    [conversation, handleRetry, isRetrying],
99	  );
100	
101	  // Filter out empty message pairs
102	  const filteredMessages = useMemo(() => {
103	    if (!convoMessages) return [];
104	
105	    return filterEmptyMessagePairs(
106	      convoMessages,
107	      conversation?.is_system_generated || false,
108	      conversation?.system_purpose ?? undefined,
109	    );
110	  }, [
111	    convoMessages,
112	    conversation?.is_system_generated,
113	    conversation?.system_purpose,
114	  ]);
115	
116	  // Deduplicate tool calls across all messages in the conversation
117	  const messagesWithDeduplicatedToolCalls = useMemo(() => {
118	    const seenToolCallIds = new Set<string>();
119	
120	    return filteredMessages.map((message) => {
121	      // Only process bot messages with tool_data
122	      if (message.type !== "bot" || !message.tool_data) {
123	        return message;
124	      }
125	
126	      // Filter out tool calls that have already been shown in previous messages
127	      const deduplicatedToolData = message.tool_data
128	        .map((entry) => {
129	          // Only deduplicate tool_calls_data entries
130	          if (entry.tool_name !== "tool_calls_data") {
131	            return entry;
132	          }
133	
134	          // Filter the tool calls array within this entry
135	          // Cast to unknown[] since we know tool_calls_data contains objects with tool_call_id
136	          const toolCallsArray = (
137	            Array.isArray(entry.data) ? entry.data : [entry.data]
138	          ) as Array<{ tool_call_id?: string }>;
139	          const filteredCalls = toolCallsArray.filter((call) => {
140	            const toolCallId = call?.tool_call_id;
141	            if (!toolCallId) return true; // Keep calls without IDs
142	            if (seenToolCallIds.has(toolCallId)) return false; // Skip duplicates
143	            seenToolCallIds.add(toolCallId);
144	            return true;
145	          });
146	
147	          // If all calls were filtered out, return null to remove this entry
148	          if (filteredCalls.length === 0) return null;
149	
150	          // Return the entry with filtered calls
151	          return {
152	            ...entry,
153	            data: filteredCalls,
154	          };
155	        })
156	        .filter((entry) => entry !== null);
157	
158	      return {
159	        ...message,
160	        tool_data: deduplicatedToolData,
161	      } as MessageType;
162	    });
163	  }, [filteredMessages]);
164	
165	  useEffect(() => {
166	    const messageId = new URLSearchParams(window.location.search).get(
167	      "messageId",
168	    );
169	    if (
170	      messageId &&
171	      messagesWithDeduplicatedToolCalls.length > 0 &&
172	      scrolledToMessageRef.current !== messageId
173	    ) {
174	      scrollToMessage(messageId);
175	      scrolledToMessageRef.current = messageId;
176	    }
177	  }, [messagesWithDeduplicatedToolCalls]);
178	
179	  const scrollToMessage = (messageId: string) => {
180	    if (!messageId) return;
181	
182	    const messageElement = document.getElementById(messageId);
183	
184	    if (!messageElement) return;
185	
186	    messageElement.scrollIntoView({ behavior: "smooth", block: "start" });
187	    messageElement.style.transition = "all 0.3s ease";
188	
189	    setTimeout(() => {
190	      messageElement.style.scale = "1.07";
191	
192	      setTimeout(() => {
193	        messageElement.style.scale = "1";
194	      }, 300);
195	    }, 700);
196	  };
197	
