interface OnboardingWorkflowCardsProps {
  workflows: OnboardingWorkflow[];
  /** Drop the `ml-10.75` indent — used when the grid is rendered inside an
   *  accordion (where the parent already handles padding). */
  embedded?: boolean;
}

function OnboardingWorkflowCardsImpl({
  workflows,
  embedded = false,
}: OnboardingWorkflowCardsProps) {
  const [activeWorkflow, setActiveWorkflow] = useState<Workflow | null>(null);
  const [isOpen, setIsOpen] = useState(false);
  const [loadingId, setLoadingId] = useState<string | null>(null);

  const handleCardClick = useCallback(
    async (workflowId: string | undefined) => {
      if (loadingId) return;
      if (!workflowId) {
        console.error("[onboarding] Workflow card clicked with no id");
        return;
      }
      setLoadingId(workflowId);
      try {
        const response = await workflowApi.getWorkflow(workflowId);
        setActiveWorkflow(response.workflow);
        setIsOpen(true);
      } catch (err) {
        console.error("Failed to load workflow", err);
      } finally {
        setLoadingId(null);
      }
    },
    [loadingId],
  );

  const handleOpenChange = useCallback((open: boolean) => {
    setIsOpen(open);
    if (!open) setActiveWorkflow(null);
  }, []);

  return (
    <>
      <m.div
        className={
          embedded
            ? "grid grid-cols-1 gap-3 sm:grid-cols-2"
            : "ml-10.75 grid grid-cols-1 gap-3 sm:grid-cols-2"
        }
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.3 }}
      >
        {workflows.map((workflow, index) => {
          const cardSteps =
            workflow.steps?.map((step, stepIndex) => ({
              id: `${workflow.id ?? index}-step-${stepIndex}`,
              category: step.category,
              title: step.title ?? "",
              description: step.description ?? "",
            })) ?? [];

          return (
            <m.div
              key={workflow.id ?? `workflow-${index}`}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{
                delay: index * 0.08,
                duration: 0.35,
                ease: EASE_OUT_QUART,
              }}
            >
              <UnifiedWorkflowCard
                title={workflow.title}
                description={workflow.description}
                steps={cardSteps}
                primaryAction="none"
                showTrigger={false}
                showExecutions={false}

